#include "lenet5_custom_tiling.h"
#include "register/op_def_registry.h"

namespace optiling {

static inline uint32_t AlignDown(uint32_t x, uint32_t a)
{
    return (x / a) * a;
}

static inline uint32_t CeilDiv(uint32_t a, uint32_t b)
{
    return (a + b - 1u) / b;
}

// UB usage estimation for one image:
// x(1x32x32)=1024, conv1_out(6x28x28)=4704, pool1(6x14x14)=1176,
// conv2_out(16x10x10)=1600, pool2(16x5x5)=400,
// fc1(120), fc2(84), fc3(numClasses) + small overhead.
// This comfortably fits in 192KB UB with tileBatch=1.
static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    Lenet5CustomTilingData tiling;

    const gert::Shape *x_shape = context->GetInputShape(0);
    if (x_shape->GetOriginShape().GetDimNum() < 4) {
        return ge::GRAPH_FAILED;
    }
    const uint32_t batch = static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(0));

    const gert::Shape *fc3_w_shape = context->GetInputShape(9);
    if (fc3_w_shape->GetOriginShape().GetDimNum() < 2) {
        return ge::GRAPH_FAILED;
    }
    const uint32_t numClasses = static_cast<uint32_t>(fc3_w_shape->GetOriginShape().GetDim(0));

    // Set tileBatch conservatively to 1 for UB stability.
    const uint32_t tileBatch = 1;

    // Adaptive blockDim based on batch
    uint32_t blockDim = (batch == 0) ? 8u : batch;
    if (blockDim < 8u) blockDim = 8u;
    if (blockDim > 24u) blockDim = 24u;
    context->SetBlockDim(blockDim);

    tiling.set_batch(batch);
    tiling.set_tileBatch(tileBatch);
    tiling.set_blockDim(blockDim);
    tiling.set_numClasses(numClasses);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

} // namespace optiling

namespace ge {
static ge::graphStatus InferShape(gert::InferShapeContext *context)
{
    const gert::Shape *x_shape = context->GetInputShape(0);
    const gert::Shape *fc3_w_shape = context->GetInputShape(9);
    if (!x_shape || !fc3_w_shape) {
        return GRAPH_FAILED;
    }
    const int64_t batch = x_shape->GetOriginShape().GetDim(0);
    const int64_t num_classes = fc3_w_shape->GetOriginShape().GetDim(0);

    gert::Shape *y_shape = context->GetOutputShape(0);
    std::vector<int64_t> out_dims = {batch, num_classes};
    y_shape->SetDimNum(2);
    for (size_t i = 0; i < out_dims.size(); ++i) {
        y_shape->SetDim(i, out_dims[i]);
    }
    return GRAPH_SUCCESS;
}

